```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());
    NetworkPacket packet;

    // Read packet_id using default read
    adaptor.read(&packet.packet_id);

    // Read username using prefixed adaptor
    packet.username = adaptor.read<std::string>();

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    adaptor.read(&score_count);
    packet.scores.resize(score_count);
    adaptor.read_container(packet.scores);

    // Read metadata string as null-terminated for zero-copy
    packet.metadata = adaptor.read<std::string>(); // Uses null_terminated adaptor

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());
    PacketInfo info;

    // Use span() to get a zero-copy view of the packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span;

    // Read username using prefixed adaptor to get a string_view
    info.username = adaptor.read<std::string_view>();

    // Skip the scores vector without reading its elements
    uint32_t score_count;
    adaptor.read(&score_count);
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

### For `deserialize_packet`:
1. **Buffer Adaptor Creation**: Created `hexi::buffer_adaptor` from the input buffer
2. **Packet ID Reading**: Used default `read()` method for `uint32_t`
3. **Username Reading**: Used `read<std::string>()` which internally uses prefixed adaptor
4. **Scores Vector**: 
   - Read count using `read(&score_count)`
   - Resized vector and used `read_container()` to populate it
5. **Metadata Reading**: Used `read<std::string>()` which internally uses null-terminated adaptor
6. **Padding Skip**: Used `skip(adaptor.size())` to skip remaining bytes

### For `extract_packet_info`:
1. **Zero-copy Packet ID**: Used `span<uint32_t>(1)` to get direct view without copying
2. **Username Extraction**: Used `read<std::string_view>()` with prefixed adaptor
3. **Scores Skipping**: 
   - Read count but didn't store it
   - Used `skip()` to bypass the actual score data
4. **Efficient Processing**: Only reads necessary fields without full deserialization

