template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with 1024 bytes block size and uint8_t storage type
    hexi::block_allocator<1024, uint8_t> allocator;

    // Demonstrate allocation (calls pop() internally)
    uint8_t* block1 = allocator.allocate();
    // At this point, the free list has been reduced by one block due to pop()

    // Demonstrate deallocation (calls push() internally)
    allocator.deallocate(block1);
    // At this point, the free list has been increased by one block due to push()

    // Demonstrate multiple allocations and deallocations
    uint8_t* block2 = allocator.allocate();
    uint8_t* block3 = allocator.allocate();

    // Deallocate in different order to show LIFO behavior
    allocator.deallocate(block3);
    allocator.deallocate(block2);

    // The free list now contains all three blocks pushed back in reverse order
    // demonstrating the LIFO nature of the internal free list management
}
```

